import React from 'react'
import { Link } from 'react-router-dom'

const Navbar = () => {
    const links =[
      {
        name:"Home",
        to:"/",
      },
      {
        name:"All Calculators",
        to:"/all-calculators",
      },
      {
        name:"Profile",
        to:"/profile",
      },
      {
        name:"Login",
        to:"/login",
      },
    ]

  return (
    <div>
      <div className="HomePage">
        <Link to="">
          Главная
        </Link>
      </div>
    </div>
  )
}

export default Navbar
